import React from 'react'
import ReactApexChart from 'react-apexcharts'
import ApexCharts from 'apexcharts'
import './styles.css'

// Facet (#13): register named themes ONCE (palette + design tokens + mode).
// Any chart can then reference one by name via theme:{ name }, and switching
// themes is a single updateOptions call.
ApexCharts.registerTheme('sunset', {
  palette: ['#ff6b6b', '#f06595', '#cc5de8', '#845ef7', '#ff922b'],
  tokens: { fore: '#5c3d2e', grid: '#f3d9c4', surface: '#fff8f2' },
})
ApexCharts.registerTheme('ocean', {
  palette: ['#0ca678', '#1098ad', '#1971c2', '#3b5bdb', '#0b7285'],
  tokens: { fore: '#0b3d4d', grid: '#c5e4ec', surface: '#f2fbfd' },
})
ApexCharts.registerTheme('slate', {
  mode: 'dark',
  palette: ['#94a3b8', '#38bdf8', '#a78bfa', '#f472b6', '#fbbf24'],
  tokens: { fore: '#e2e8f0', grid: '#334155', surface: '#0f172a' },
})

const ApexChart = () => {
  const [state, setState] = React.useState({
    series: [{ name: 'Revenue', data: [44, 62, 51, 38, 47] }],
    options: {
      chart: {
        id: 'facetBrandChart',
        height: 400,
        type: 'bar',
        fontFamily: 'sans-serif',
        animations: { enabled: true },
        toolbar: { show: false },
      },
      theme: {
        name: 'sunset',
      },
      plotOptions: {
        bar: { columnWidth: '55%', borderRadius: 4, distributed: true },
      },
      dataLabels: { enabled: false },
      legend: { show: false },
      title: {
        text: 'Revenue by channel',
        align: 'left',
      },
      subtitle: {
        text: 'Palette and chrome come from a registered brand theme',
        align: 'left',
      },
      xaxis: {
        type: 'category',
        categories: ['Direct', 'Search', 'Social', 'Email', 'Referral'],
      },
    },
  })

  React.useEffect(() => {
    // The react-apexcharts wrapper owns the render, so reach the live instance by
    // its chart.id at event time. The dropdown lives in the html block (not the
    // chart wrapper), so it is in the DOM by the time this effect runs.
    const pick = document.getElementById('themePick')
    const onChange = (e) => {
      const chart = ApexCharts.getChartByID('facetBrandChart')
      if (chart) chart.updateOptions({ theme: { name: e.target.value } })
    }
    pick.addEventListener('change', onChange)
    return () => pick.removeEventListener('change', onChange)
  }, [])

  return (
    <div>
      <div className="panel">
        <div className="controls">
          <label>
            Theme:
            <select id="themePick">
              <option value="sunset" selected>
                sunset
              </option>
              <option value="ocean">ocean</option>
              <option value="slate">slate (dark)</option>
            </select>
          </label>
        </div>
      </div>

      <div id="chart">
        <ReactApexChart
          options={state.options}
          series={state.series}
          type="bar"
          height={400}
        />
      </div>

      <div className="panel">
        <div className="note">
          Three themes are registered once with
          <code>
            ApexCharts.registerTheme(name, &#123; palette, tokens, mode &#125;)
          </code>
          . The chart references one via{' '}
          <code>theme: &#123; name: 'sunset' &#125;</code> and the dropdown
          switches with{' '}
          <code>
            chart.updateOptions(&#123; theme: &#123; name &#125; &#125;)
          </code>
          . A registered theme sits below explicit config and CSS{' '}
          <code>--apx-*</code>
          tokens, so a page-level token can still override a brand default.
        </div>
      </div>
    </div>
  )
}

export default ApexChart

#chart {
  max-width: 720px;
  margin: 16px auto;
}
.panel {
  max-width: 720px;
  margin: 16px auto;
  font-family: sans-serif;
}
