  background: #f6f6fb;
  border-left: 3px solid #6c5ce7;
  padding: 10px 14px;
  font-size: 13px;
  color: #234;
  border-radius: 2px;
  line-height: 1.55;
}
.note code {
  background: #e9e7fb;
  padding: 1px 5px;
  border-radius: 3px;
}
